assigned_numbers = input().split()

seen = set()
duplicates = set()
ordered_duplicates = []

for number in assigned_numbers:
    if number in seen:
        if number not in duplicates:
            ordered_duplicates.append(number)
            duplicates.add(number)
    else:
        seen.add(number)

if ordered_duplicates:
    print(" ".join(ordered_duplicates))
else:
    print("No duplicates.")
